module RefModule (
    input clk,
    input rst,
    input [7:0] seed,
    output reg [7:0] lfsr_out
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            lfsr_out <= seed;
        end else begin
            // LFSR feedback polynomial: x^8 + x^6 + x^5 + x^4 + 1
            lfsr_out <= {lfsr_out[6:0], lfsr_out[7] ^ lfsr_out[5] ^ lfsr_out[4] ^ lfsr_out[3]};
        end
    end
endmodule
